solutionCode:
function estimatePriceImpact(poolSize, tradeSize) {
  const raw = (tradeSize / poolSize) * 100;
  const impactPct = Math.round(raw * 100) / 100;
  return {
    impactPct,
    highImpact: impactPct >= 5,
  };
}

testCode:
const r1 = estimatePriceImpact(100000, 1000);
assert(r1.impactPct === 1, 'impact should be 1%');
assert(r1.highImpact === false, 'should not be high impact');

const r2 = estimatePriceImpact(100000, 7000);
assert(r2.impactPct === 7, 'impact should be 7%');
assert(r2.highImpact === true, 'should be high impact');
